THE RISK:
{
 "id": "large-operator-qualification-tunnel",
 "title": "'Large operators first' aims the launch at the one channel that cannot buy inside 12 months",
 "narrative": "The venture's stated first channel is large operators — and the model rewards that choice with the biggest buyer node (0.40, the widest-swing customer share). But that 0.40 is an internal estimate resting on a single misread order-mix statistic, and it says nothing about ACCESS. Large colo and hyperscale operators buy rack power through approved-vendor lists and framework agreements: qualification (CE/TÜV, EN 50600 alignment, firmware security review, DCIM interoperability, pilot pods) routinely runs 12–24 months for a new hardware vendor. For a pre-launch entrant, the large-operator slice is not a smaller number — it is unavailable inside the YAM window. Year-1 reachable demand collapses onto OEM/integrator and distributor channels the model weights at only 0.35 combined and has never validated.",
 "category": "execution",
 "targetNodes": [
  "cust.operator-large"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The go-to-market plan names large operators as the first buyer, and the model assigns them the dominant 0.40 buyer share — a share whose only evidence is one supplier's company-level order mix, with the ledger itself flagging 'internal estimate, no published channel split'",
   "refs": [
    "profile:Stage",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "propagation",
   "text": "Large operators' near-term deliveries are pre-let (83%) and vendor-committed under frameworks with a semi-consolidated incumbent set (CR3 ~0.55); a new vendor must first clear AVL qualification, which for powered rack hardware exceeds the venture's entire 12-month horizon — so the channel is sequentially blocked, not just competitive",
   "refs": [
    "digest:geo-DE#c21",
    "ledger:shape.cr3"
   ]
  },
  {
   "step": "model-impact",
   "text": "Within the YAM window the operator-large cell is foreclosed: Year-1 obtainable demand must route through OEM/integrator (0.22) and distributor (0.13) cells — both zero-evidence estimates — shrinking reachable SAM by the excluded share",
   "refs": [
    "ledger:cust.oem",
    "ledger:cust.distributor",
    "ledger:cust.operator-large"
   ]
  }
 ],
 "whyMissable": "Choosing the biggest buyer as the first target looks like focus, and the model validates it by making that buyer the largest node. The surface appearance — 'we're going where the money is' — hides a sequencing constraint: the size of a channel and the speed of entry into it are different variables, and the model only encodes the first.",
 "expectedObviousness": "medium",
 "falsifier": "A documented case (or direct confirmation from a CE large operator's procurement team) of a new rack-PDU vendor moving from first contact to purchase order in under 9 months, including qualification and pilot.",
 "likelihood": {
  "value": 0.58,
  "rationale": "Vendor-qualification timelines of 12+ months for powered rack hardware at large operators are the industry norm (base rate for new-entrant hardware onboarding at enterprise/hyperscale accounts), and nothing in the venture's pre-launch position shortens them; partial exceptions exist via urgent-capacity waivers. [evidence revision: Evidence robustly confirms the existence and rigor of formal qualification/prequalification gates at large operators and hyperscalers (the mechanism's structural premise). No falsifying sub-9-month case surfaced. But the specific 12–24 month duration remains uncorroborated by direct quantitative evidence, so only a modest upward adjustment from 0.55 is warranted.]",
  "basis": "evidence",
  "revisedFrom": 0.55
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "exclude",
   "note": "Large-operator cell unavailable to the venture within the Year-1 window — foreclosure, not shrinkage"
  }
 ],
 "indicators": [
  {
   "signal": "Stated vendor-qualification requirements and timelines in operator supplier onboarding portals",
   "where": "Equinix, NTT GDC, Data4, Vantage supplier/procurement portals and RFQ documents",
   "threshold": "Mandatory qualification stages summing to >9 months before first PO eligibility",
   "updates": "increases"
  },
  {
   "signal": "Venture's own qualification funnel progress with the first two target operators",
   "where": "Internal CRM / operator procurement correspondence, reviewed monthly",
   "threshold": "No pilot-pod agreement signed within 4 months of launch",
   "updates": "increases"
  },
  {
   "signal": "Distributor and rack-integrator line-card openings for third-party intelligent PDUs",
   "where": "CE electrical distributor price lists (Rexel, Sonepar) and rack-integrator OEM programs",
   "threshold": "≥1 CE distributor actively onboarding a new PDU brand",
   "updates": "decreases"
  }
 ],
 "mitigations": [
  {
   "action": "Interview 3 CE operator procurement heads and 2 distributors specifically on qualification duration, AVL entry criteria, and whether any fast-track (urgent capacity) lane exists",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Also the ledger's own promotion path for the entire unsourced buyer-mix block"
  },
  {
   "action": "Enter Year 1 through OEM/rack-integrator white-label supply, where the integrator's existing AVL status carries the product into large-operator halls",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Converts the qualification tunnel from a blocker into someone else's sunk cost"
  },
  {
   "action": "Start large-operator qualification processes in parallel at launch so the channel opens in Year 2, and model Year-1 revenue exclusively on indirect channels",
   "type": "operational",
   "voiNodeId": null,
   "note": "Decouples the pipeline-building activity from the Year-1 revenue plan"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
